const body = $json.body || $json;
const headers = $json.headers || {};
if (body.workflow_key !== 'docs.from-template.v1') { throw new Error('Invalid workflow_key'); }
if (!body.invocation_id) { throw new Error('Missing invocation_id'); }
if (!body.payload || (!body.payload.template_key && !body.payload.template_id)) { throw new Error('Missing template reference'); }
if (!body.payload.title) { throw new Error('Missing payload.title'); }
if (!body.callback || !body.callback.url) { throw new Error('Missing callback.url'); }
return [{ json: { body, headers } }];

const map = {
  hop_dong_dich_vu_v1: 'REPLACE_WITH_GOOGLE_TEMPLATE_ID',
  bao_gia_v1: 'REPLACE_WITH_GOOGLE_TEMPLATE_ID'
};
const templateId = $json.template_id || map[$json.template_key];
if (!templateId) { throw new Error(`Cannot resolve template_id for key: ${$json.template_key}`); }
return [{ json: { ...$json, template_id: templateId } }];

const data = $json.data || {};
const requests = Object.entries(data).map(([key, value]) => ({
  replaceAllText: {
    containsText: { text: `{{${key}}}`, matchCase: true },
    replaceText: String(value ?? '')
  }
}));
return [{ json: { ...$json, requests } }];
